mapper.select:
SELECT m.id, m.file_id, f.original_name, f.file_size, f.mime_type, f.extension, f.storage_type, 'report_material' AS business_type, m.material_category AS business_id, f.is_private, f.access_url, f.upload_time, f.download_count FROM ai_report_material m INNER JOIN sys_file_metadata f ON f.file_id = m.file_id AND f.status = 1
m.status = 1 AND m.tenant_id = #{tenantId}
AND m.material_category = #{materialCategory}
AND f.original_name LIKE CONCAT('%', #{originalName}, '%')
AND f.mime_type LIKE CONCAT(#{mimeType}, '%')
AND f.is_private = #{isPrivate}
AND (f.is_private = 0 OR f.uploader_id = #{currentUserId})
ORDER BY f.upload_time DESC, m.create_time DESC

SELECT 
FROM ai_report_material
WHERE tenant_id = #{tenantId}
  AND file_id = #{fileId}
  AND status = 1
LIMIT 1

mapper.update:
UPDATE ai_report_material
SET status = 0,
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND file_id = #{fileId}
  AND status = 1
